import{_ as a,a as t}from"./chunks/layout-editor-panel-dark.BIiFq4Mb.js";import{_ as r,a as o}from"./chunks/key-properties-panel-dark._vXv5Kvs.js";import{_ as i,a as s}from"./chunks/keyboard-metadata-panel-dark.fhBUhBMn.js";import{_ as n,a as l}from"./chunks/summary-panel-dark.BFH-8WeJ.js";import{_ as d,a as c}from"./chunks/plate-generator-panel-dark.zYB_e9jb.js";import{_ as h,a as p}from"./chunks/pcb-generator-panel-dark.BCzVKhJW.js";import{_ as m,o as u,c as g,ag as y}from"./chunks/framework.Cbg42_iJ.js";const f="/docs/json-editor-panel-light.png",k="/docs/json-editor-panel-dark.png",B=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started.md","filePath":"getting-started.md"}'),b={name:"getting-started.md"};function S(x,e,P,_,C,w){return u(),g("div",null,[...e[0]||(e[0]=[y('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>The kle-ng runs entirely in your web browser — no installation required. Visit <a href="https://editor.keyboard-tools.xyz/" target="_blank" rel="noreferrer">editor.keyboard-tools.xyz</a> and start creating or editing keyboard layouts immediately.</p><h2 id="interface-overview" tabindex="-1">Interface Overview <a class="header-anchor" href="#interface-overview" aria-label="Permalink to &quot;Interface Overview&quot;">​</a></h2><h3 id="layout-editor" tabindex="-1">Layout Editor <a class="header-anchor" href="#layout-editor" aria-label="Permalink to &quot;Layout Editor&quot;">​</a></h3><p>The main editing area where keys are displayed and manipulated. Click to select individual keys, drag to box-select multiple keys, and use side toolbar to launch editing tools.</p><img src="'+a+'" class="docs-screenshot light-only" alt="Layout editor canvas with a keyboard layout"><img src="'+t+'" class="docs-screenshot dark-only" alt="Layout editor canvas with a keyboard layout"><h3 id="key-properties" tabindex="-1">Key Properties <a class="header-anchor" href="#key-properties" aria-label="Permalink to &quot;Key Properties&quot;">​</a></h3><p>Controls position, size, labels, colors, and key options (ghost, stepped, homing nub, etc.). Changes apply immediately to the canvas. Controls are activated when one or more keys are selected. Properties are applied to all selected keys.</p><img src="'+r+'" class="docs-screenshot light-only" alt="Key Properties panel"><img src="'+o+'" class="docs-screenshot dark-only" alt="Key Properties panel"><h3 id="keyboard-metadata" tabindex="-1">Keyboard Metadata <a class="header-anchor" href="#keyboard-metadata" aria-label="Permalink to &quot;Keyboard Metadata&quot;">​</a></h3><p>Layout-wide settings: name, author, background color, border radius, key spacing (mm/U), custom CSS, and VIA metadata. The CSS field accepts standard CSS and is useful for applying custom fonts — see <a href="./custom-fonts.html">Custom Fonts</a> for details. The VIA metadata section stores matrix size and key assignments needed by VIA-compatible firmware — see <a href="./via-and-metadata.html">VIA &amp; Vial Format</a> for details.</p><img src="'+i+'" class="docs-screenshot light-only" alt="Keyboard Metadata panel"><img src="'+s+'" class="docs-screenshot dark-only" alt="Keyboard Metadata panel"><h3 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Shows layout statistics (key count, dimensions) and a table of key center positions. Includes a CSV export of all key data.</p><img src="'+n+'" class="docs-screenshot light-only" alt="Summary panel"><img src="'+l+'" class="docs-screenshot dark-only" alt="Summary panel"><h3 id="json-editor" tabindex="-1">JSON Editor <a class="header-anchor" href="#json-editor" aria-label="Permalink to &quot;JSON Editor&quot;">​</a></h3><p>Lets you view and edit the raw KLE JSON directly. Syncing changes with canvas requires clicking <strong>Apply Changes</strong> button.</p><img src="'+f+'" class="docs-screenshot light-only" alt="JSON editor panel"><img src="'+k+'" class="docs-screenshot dark-only" alt="JSON editor panel"><h3 id="plate-generator" tabindex="-1">Plate Generator <a class="header-anchor" href="#plate-generator" aria-label="Permalink to &quot;Plate Generator&quot;">​</a></h3><p>Generates switch and stabilizer cutout files for manufacturing keyboard plates. Supports Cherry MX, Alps, and Kailh Choc switch types, and exports to SVG, DXF, STL, and JSCAD. See <a href="./plate-generator.html">Plate Generator</a> for full details.</p><img src="'+d+'" class="docs-screenshot light-only" alt="Plate generator panel"><img src="'+c+'" class="docs-screenshot dark-only" alt="Plate generator panel"><h3 id="pcb-generator" tabindex="-1">PCB Generator <a class="header-anchor" href="#pcb-generator" aria-label="Permalink to &quot;PCB Generator&quot;">​</a></h3><p>Generates a KiCad PCB project file from your layout, with switch footprints placed at the correct positions and a routed switch matrix. Requires matrix coordinates assigned to all keys beforehand. See <a href="./pcb-generator.html">PCB Generator</a> for full details.</p><img src="'+h+'" class="docs-screenshot light-only" alt="PCB generator panel"><img src="'+p+'" class="docs-screenshot dark-only" alt="PCB generator panel"><h2 id="the-unit-system" tabindex="-1">The Unit System <a class="header-anchor" href="#the-unit-system" aria-label="Permalink to &quot;The Unit System&quot;">​</a></h2><p>All key positions and sizes in kle-ng are expressed in <strong>U</strong> (keyboard units). One U is the width of a standard alphanumeric key (for example, <code>A</code>, <code>S</code>, <code>D</code>).</p><h3 id="common-key-sizes" tabindex="-1">Common Key Sizes <a class="header-anchor" href="#common-key-sizes" aria-label="Permalink to &quot;Common Key Sizes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Size</th><th>Example keys</th></tr></thead><tbody><tr><td>1U</td><td>Standard alphanumeric keys</td></tr><tr><td>1.25U</td><td><code>Tab</code>, <code>\\</code> on some layouts</td></tr><tr><td>1.5U</td><td><code>Tab</code> on standard ANSI layouts</td></tr><tr><td>2U</td><td>Numpad <code>0</code>, some <code>Backspace</code> keys</td></tr><tr><td>6.25U</td><td>Standard spacebar</td></tr></tbody></table><h3 id="physical-spacing" tabindex="-1">Physical Spacing <a class="header-anchor" href="#physical-spacing" aria-label="Permalink to &quot;Physical Spacing&quot;">​</a></h3><p>The physical size of 1U is <strong>19.05 mm</strong> by default (Cherry MX standard). You can change the mm/U ratio in the <strong>Keyboard Metadata</strong> panel if your layout uses a different switch pitch (for example, Kailh Choc low-profile at 18mm). This is important when using kle-ng&#39;s plate or PCB generators.</p><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h2><h3 id="starting-out" tabindex="-1">Starting Out <a class="header-anchor" href="#starting-out" aria-label="Permalink to &quot;Starting Out&quot;">​</a></h3><ol><li><strong>New layout</strong> — The editor starts with a sample layout. Use the toolbar to import an existing layout or start editing.</li><li><strong>Select keys</strong> — Click a key on the canvas to select it. Click and drag to select multiple keys.</li><li><strong>Edit properties</strong> — With a key selected, adjust its properties (size, color, labels) in the <strong>Key Properties</strong> panel.</li></ol><h3 id="saving-your-work" tabindex="-1">Saving Your Work <a class="header-anchor" href="#saving-your-work" aria-label="Permalink to &quot;Saving Your Work&quot;">​</a></h3><ol start="4"><li><strong>Undo</strong> — Press <kbd>Ctrl</kbd>+<kbd>Z</kbd> to undo. The editor maintains up to 50 undo steps.</li><li><strong>Export</strong> — Click <strong>Export</strong> in the toolbar to download your layout in the desired format.</li></ol><h2 id="common-workflows" tabindex="-1">Common Workflows <a class="header-anchor" href="#common-workflows" aria-label="Permalink to &quot;Common Workflows&quot;">​</a></h2><h3 id="design-a-layout-from-scratch" tabindex="-1">Design a Layout from Scratch <a class="header-anchor" href="#design-a-layout-from-scratch" aria-label="Permalink to &quot;Design a Layout from Scratch&quot;">​</a></h3><ol><li>The editor opens with a sample layout. To start fresh, select all keys with <kbd>Ctrl</kbd>+<kbd>A</kbd> and delete them with <kbd>Del</kbd>.</li><li>Press <kbd>A</kbd> to add a key. A 1U key appears at position (0, 0).</li><li>Adjust its position and size in the <strong>Key Properties</strong> panel, or use keyboard shortcuts to nudge and resize.</li><li>Continue adding keys and arranging them. Use dedicated tools from right side toolbar to apply rotations or to duplicate symmetric halves of split layouts.</li><li>Export as KLE JSON to save your work.</li></ol><h3 id="edit-an-existing-layout" tabindex="-1">Edit an Existing Layout <a class="header-anchor" href="#edit-an-existing-layout" aria-label="Permalink to &quot;Edit an Existing Layout&quot;">​</a></h3><ol><li>Click <strong>Import</strong> in the toolbar and choose <strong>From File</strong>, or drag a JSON file onto the canvas.</li><li>Select keys to modify their labels, colors, or dimensions.</li><li>Use <strong>Extra Tools → Add Switch Matrix Coordinates</strong> if you need VIA matrix assignments.</li><li>Export in the format you need.</li></ol><h3 id="generate-a-plate-for-manufacturing" tabindex="-1">Generate a Plate for Manufacturing <a class="header-anchor" href="#generate-a-plate-for-manufacturing" aria-label="Permalink to &quot;Generate a Plate for Manufacturing&quot;">​</a></h3><ol><li>Complete your layout design and verify key positions.</li><li>Open the <strong>Plate Generator</strong> panel and configure switch type and outline.</li><li>Download as SVG or DXF for laser cutting, or STL/JSCAD for 3D printing.</li></ol><p>See <a href="./plate-generator.html">Plate Generator</a> for full details.</p><h3 id="generate-a-pcb" tabindex="-1">Generate a PCB <a class="header-anchor" href="#generate-a-pcb" aria-label="Permalink to &quot;Generate a PCB&quot;">​</a></h3><ol><li>Assign matrix coordinates to all keys using <strong>Extra Tools → Add Switch Matrix Coordinates</strong>.</li><li>Open the <strong>PCB Generator</strong> panel and click <strong>Generate PCB</strong>.</li><li>Download the zip archive with <code>.kicad_sch</code> and <code>.kicad_pcb</code> files and open it in KiCad 9+.</li></ol><p>See <a href="./pcb-generator.html">PCB Generator</a> for full details.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./layout-editor.html">Layout Editor</a> — Learn all the canvas tools, keyboard shortcuts, and mouse controls</li><li><a href="./import-export.html">Import &amp; Export</a> — Supported formats and import methods</li><li><a href="./plate-generator.html">Plate Generator</a> — Create manufacturing-ready plate files</li><li><a href="./pcb-generator.html">PCB Generator</a> — Generate KiCad PCB projects</li></ul><h2 id="external-references" tabindex="-1">External References <a class="header-anchor" href="#external-references" aria-label="Permalink to &quot;External References&quot;">​</a></h2><ul><li><a href="https://github.com/adamws/kicad-kbplacer" target="_blank" rel="noreferrer">KiCad plugin for automatic keyboard&#39;s key placement and routing</a></li><li><a href="https://adamws.github.io/modifying-ergogen-layouts-without-learning-ergogen/" target="_blank" rel="noreferrer">Modifying ergogen layouts without learning ergogen</a></li></ul>',57)])])}const U=m(b,[["render",S]]);export{B as __pageData,U as default};
